mapper.select:
SELECT *
FROM product_term_versions
WHERE terms_no = #{termsNo}
AND term_version_no = (
SELECT MAX(term_version_no)
FROM product_term_versions
WHERE terms_no = #{termsNo}
)

mapper.insert:

    SELECT seq_product_term_versions.NEXTVAL FROM dual

INSERT INTO product_term_versions (
term_version_no, terms_no, major_version, minor_version,
terms_title, pdf_path, terms_text, change_reason,
effective_dt, expired_dt, is_current, created_dt, created_by
) VALUES (
#{termVersionNo}, #{termsNo}, #{majorVersion}, #{minorVersion},
#{termsTitle}, #{pdfPath}, #{termsText}, #{changeReason},
SYSDATE, NULL, 'Y', SYSDATE, #{createdBy}
)
